// 1. הגדרת זמן: 24 שעות אחורה
const twentyFourHoursAgo = new Date(Date.now() - 24 * 60 * 60 * 1000);

// 2. הגדרות סינון
const clOnlyNodes = ['Atletico Madrid', 'Real Madrid', 'Arsenal', 'Bayern Munich', 'Milan', 'Inter'];
const clKeywords = ['champions league', 'ucl', 'ליגת האלופות'];
const f1Keywords = ['race highlights', 'qualifying highlights', 'sprint highlights'];
const generalHighlights = ['highlight', 'highlights', 'recap', 'תקציר', 'full game'];
const topTenKeyword = 'top 10';

// 3. ביצוע הסינון
const filteredItems = items.filter(i => {
    const title = (i.json.title || "").toLowerCase();
    const author = (i.json.author || "").toLowerCase();
    const link = (i.json.link || "").toLowerCase();
    const pubDate = new Date(i.json.pubDate);
    const nodeName = i.main?.[0]?.node?.name || "";

    if (!i.json.pubDate || isNaN(pubDate)) return false;
    if (pubDate < twentyFourHoursAgo) return false;

    const hasHighlightKeyword = generalHighlights.some(key => title.includes(key));
    const hasTopTen = title.includes(topTenKeyword);
    const isIsraelContext =
        title.includes('israel') ||
        title.includes('ישראל') ||
        title.includes('maccabi') ||
        title.includes('hapoel');

    if (nodeName === 'FIBA' || title.includes('fiba') || author.includes('fiba')) {
        return isIsraelContext || hasTopTen;
    }

    if (
        nodeName === 'EuroLeague' ||
        nodeName === 'NBA' ||
        title.includes('euroleague') ||
        title.includes('nba') ||
        author.includes('euroleague') ||
        author.includes('nba')
    ) {
        return hasHighlightKeyword || hasTopTen;
    }

    if (
        nodeName === 'F1' ||
        author.includes('formula 1') ||
        title.includes('grand prix') ||
        title.includes('formula 1') ||
        title.includes('f1') ||
        link.includes('formula1')
    ) {
        return f1Keywords.some(key => title.includes(key));
    }

    if (clOnlyNodes.includes(nodeName)) {
        return clKeywords.some(key => title.includes(key));
    }

    if (nodeName === 'Manchester United') {
        if (title.includes('u18') || title.includes('u21') || title.includes('women')) return false;
        return hasHighlightKeyword;
    }

    if (
        nodeName === 'Bundesliga' ||
        nodeName === 'BVB' ||
        title.includes('bundesliga') ||
        author.includes('bundesliga')
    ) {
        return hasHighlightKeyword;
    }

    return false;
});

if (filteredItems.length === 0) return [];

// 4. שליחת רשימה נקייה ומסודרת לסוכן
const cleanList = filteredItems.map(i => {
    const cleanTitle = (i.json.title || "").replace(/\n/g, ' ').trim();
    return `${cleanTitle} | ${i.json.link}`;
}).join('\n');

return [
  {
    json: {
      text: cleanList
    }
  }
];

const response = items[0].json.output;
if (!response || response.includes('IGNORE')) return [];

// 1. פיצול וניקוי בסיסי
let matches = response.split(/\n|\\n/)
    .map(line => line.trim())
    .filter(line => line.includes('|'))
    .map(line => {
        const parts = line.split('|').map(p => p.trim());
        return { 
            name: parts[0], 
            league: parts[1], 
            link: parts[2]?.split(' ')[0] 
        };
    });

// 2. הגדרות עדיפות ואימוג'ים
const leagueSettings = {
    'F1': { priority: 1, icon: '🏎️' },
    'FIBA': { priority: 2, icon: '🏀' },
    'EuroLeague': { priority: 3, icon: '🏀' },
    'NBA': { priority: 4, icon: '🏀' },
    'UCL': { priority: 5, icon: '🏆' },
    'Bundesliga': { priority: 6, icon: '⚽' },
    'Manchester United': { priority: 7, icon: '⚽' }
};

// 3. מיון לפי עדיפות (Priority)
matches.sort((a, b) => {
    const priorityA = leagueSettings[a.league]?.priority || 99;
    const priorityB = leagueSettings[b.league]?.priority || 99;
    return priorityA - priorityB;
});

// 4. עיבוד סופי - הוספת אייקונים ומבנה n8n
return matches.map(m => {
    const isIsrael = /israel|ישראל|maccabi|hapoel/i.test(m.name);

    // לוגיקה: ישראל מקבלת דגל, כל השאר לפי האייקון של הליגה
    let icon = isIsrael ? '🇮🇱' : (leagueSettings[m.league]?.icon || '⚽');

    return {
        json: { 
            name: m.name, 
            league: `${icon} ${m.league}`, 
            link: m.link 
        }
    };
});

// רשימת כל הליגות והקישורים שלהן - קל להוסיף/למחוק מכאן
const feeds = [
  { url: "https://www.youtube.com/feeds/videos.xml?channel_id=UCB_qr75-ydFVKSF9Dmo6izg", league: "F1" },
  { url: "https://www.youtube.com/feeds/videos.xml?channel_id=UC0LrZO9wORIqn_aRJtKdgfA", league: "NBA" },
  { url: "https://www.youtube.com/feeds/videos.xml?channel_id=UCGr3nR_XH9r6E5b09ZJAT9w", league: "EuroLeague" },
  { url: "https://www.youtube.com/feeds/videos.xml?channel_id=UCtInrnU3QbWqFGsdKT1GZtg", league: "FIBA" },
  { url: "https://www.youtube.com/feeds/videos.xml?channel_id=UC6UL29enLNe4mqwTfAyeNuw", league: "Bundesliga" },
  { url: "https://www.youtube.com/feeds/videos.xml?channel_id=UC6yW44UGJJBvYTlfC7CRg2Q", league: "Manchester United" },
  { url: "https://www.youtube.com/feeds/videos.xml?channel_id=UCWV3obpZVGgJ3j9FVhEjF2Q", league: "Real Madrid" },
  { url: "https://www.youtube.com/feeds/videos.xml?channel_id=UCK8rTVgp3-MebXkmeJcQb1Q", league: "BVB" },
  { url: "https://www.youtube.com/feeds/videos.xml?channel_id=UCuzKFwdh7z2GHcIOX_tXgxA", league: "Atletico Madrid" },
  { url: "https://www.youtube.com/feeds/videos.xml?channel_id=UCpryVRk_VDudG8SHXgWcG0w", league: "Arsenal" },
  { url: "https://www.youtube.com/feeds/videos.xml?channel_id=UCZkcxFIsqW5htimoUQKA0iA", league: "Bayern" }
];

return feeds.map(feed => ({ json: feed }));
